r_mwa_max_lon_50_nest_sum.sql:
select ( select count(membership_no) from sc_mem_m_membership_registered where sc_mem_m_membership_registered.member_status_code = '0' and sc_mem_m_membership_registered.mem_type = '01' ) as count_mem
/*สมาชิกสามัญ (ราย)*/ ,( select count( distinct sc_mem_m_membership_registered.membership_no ) from sc_lon_m_loan_card ,sc_lon_m_contract ,sc_mem_m_membership_registered ,sc_cls_confirm_data where sc_lon_m_loan_card.loan_contract_no = sc_lon_m_contract.loan_contract_no and sc_mem_m_membership_registered.membership_no = sc_lon_m_loan_card.membership_no and sc_mem_m_membership_registered.membership_no = sc_cls_confirm_data.membership_no and sc_cls_confirm_data.data_refno = sc_lon_m_contract.loan_contract_no and sc_lon_m_loan_card.principal_balance > 0 and sc_mem_m_membership_registered.member_status_code = '0' and sc_mem_m_membership_registered.mem_type = '01' and sc_lon_m_loan_card.loan_type not in ('สอ') /*ไม่รวม สหกรณ์อื่น ๆ*/ and sc_cls_confirm_data.confirm_date = {0} ) as count_mem_norm
,( select nvl(sum( sc_lon_m_loan_card.principal_balance ),0) from sc_lon_m_loan_card ,sc_lon_m_contract ,sc_mem_m_membership_registered ,sc_cls_confirm_data where sc_lon_m_loan_card.loan_contract_no = sc_lon_m_contract.loan_contract_no and sc_mem_m_membership_registered.membership_no = sc_lon_m_loan_card.membership_no and sc_mem_m_membership_registered.membership_no = sc_cls_confirm_data.membership_no and sc_cls_confirm_data.data_refno = sc_lon_m_contract.loan_contract_no and sc_lon_m_loan_card.principal_balance > 0 and sc_mem_m_membership_registered.member_status_code = '0' and sc_mem_m_membership_registered.mem_type = '01' and sc_lon_m_loan_card.loan_type not in ('สอ') /*ไม่รวม สหกรณ์อื่น ๆ*/ and sc_cls_confirm_data.confirm_date = {0} ) as principal_balance_norm
/*สมาชิกสมทบ (ราย)*/ ,( select count( distinct sc_mem_m_membership_registered.membership_no ) from sc_lon_m_loan_card ,sc_lon_m_contract ,sc_mem_m_membership_registered ,sc_cls_confirm_data where sc_lon_m_loan_card.loan_contract_no = sc_lon_m_contract.loan_contract_no and sc_mem_m_membership_registered.membership_no = sc_lon_m_loan_card.membership_no and sc_mem_m_membership_registered.membership_no = sc_cls_confirm_data.membership_no and sc_cls_confirm_data.data_refno = sc_lon_m_contract.loan_contract_no and sc_lon_m_loan_card.principal_balance > 0 and sc_mem_m_membership_registered.member_status_code = '0' and sc_mem_m_membership_registered.member_group_no = 'a8000' and sc_lon_m_loan_card.loan_type not in ('สอ') /*ไม่รวม สหกรณ์อื่น ๆ*/ and sc_cls_confirm_data.confirm_date = {0} ) as count_mem_ass
,( select nvl(sum( sc_lon_m_loan_card.principal_balance ),0) from sc_lon_m_loan_card ,sc_lon_m_contract ,sc_mem_m_membership_registered ,sc_cls_confirm_data where sc_lon_m_loan_card.loan_contract_no = sc_lon_m_contract.loan_contract_no and sc_mem_m_membership_registered.membership_no = sc_lon_m_loan_card.membership_no and sc_mem_m_membership_registered.membership_no = sc_cls_confirm_data.membership_no and sc_cls_confirm_data.data_refno = sc_lon_m_contract.loan_contract_no and sc_lon_m_loan_card.principal_balance > 0 and sc_mem_m_membership_registered.member_status_code = '0' and sc_mem_m_membership_registered.member_group_no = 'a8000' and sc_lon_m_loan_card.loan_type not in ('สอ') /*ไม่รวม สหกรณ์อื่น ๆ*/ and sc_cls_confirm_data.confirm_date = {0} ) as principal_balance_ass
/*ยอดรวมลูกหนี้เงินให้กู้ยืมรายใหญ่ (บุคคล)*/ ,( select sum( sc_cls_confirm_data.data_balance) FROM sc_cls_confirm_data, sc_mem_m_membership_registered, sc_mem_m_ucf_prename, sc_lon_m_rule, sc_lon_m_contract ,sc_acc_m_account_constant ,sc_mem_m_ucf_member_type
,( select sum(1)over(order by sum_principal_balance desc ) as seq_no /*เทียบเท่า comulative sum ถ้าเอา 50 คน ก้อเอา seq_no <= 50 */ ,membership_no ,sum_principal_balance from ( select sc_cls_confirm_data.membership_no ,sum(sc_cls_confirm_data.data_balance) as sum_principal_balance from sc_cls_confirm_data ,sc_lon_m_rule where sc_lon_m_rule.loan_type = sc_cls_confirm_data.data_type and sc_cls_confirm_data.data_group = 'LON' and sc_lon_m_rule.invest_status = '0' and sc_lon_m_rule.loan_type not in ( 'สอ' ) /*WHERE*/ --and sc_cls_confirm_data.confirm_date = '28/06/2024' group by sc_cls_confirm_data.membership_no order by sum_principal_balance desc /*เรียงหนี้รวม จากมากไปหาน้อย*/ ) tab1 ) tab2 WHERE ( sc_mem_m_membership_registered.membership_no = sc_cls_confirm_data.membership_no ) and ( sc_mem_m_membership_registered.prename_code = sc_mem_m_ucf_prename.prename_code ) and ( sc_cls_confirm_data.data_type = sc_lon_m_rule.loan_type ) and ( sc_cls_confirm_data.data_refno = sc_lon_m_contract.loan_contract_no ) and sc_mem_m_ucf_member_type.mem_type_code = sc_mem_m_membership_registered.mem_type and sc_cls_confirm_data.membership_no = tab2.membership_no and sc_cls_confirm_data.data_group = 'LON' and sc_lon_m_rule.invest_status = '0' and sc_lon_m_rule.loan_type not in ( 'สอ' ) and sc_cls_confirm_data.confirm_date = {0} and tab2.seq_no <= '!seq_no_1!' ) as principal_balance_max_50
/*จำนวนบุคคลอื่นที่สหกรณ์ให้เงินกู้ยืมทั้งหมด (ราย)*/ ,( SELECT count( distinct sc_rep_mem_share_loan_year.membership_no ) FROM sc_rep_mem_share_loan_year ,sc_mem_m_membership_registered WHERE ( sc_rep_mem_share_loan_year.membership_no = sc_mem_m_membership_registered.membership_no ) and sc_rep_mem_share_loan_year.balance_date = '!confirm_date!' and sc_mem_m_membership_registered.member_group_no in ('9499','9498','a9000') and sc_rep_mem_share_loan_year.client_id = '000' and ( sc_rep_mem_share_loan_year.emer_balance > 0 or sc_rep_mem_share_loan_year.norm_balance > 0 or sc_rep_mem_share_loan_year.spec_balance > 0) ) as count_mem_coop
,( SELECT sum(sc_rep_mem_share_loan_year.norm_balance +sc_rep_mem_share_loan_year.emer_balance +sc_rep_mem_share_loan_year.spec_balance) as amount FROM sc_rep_mem_share_loan_year ,sc_mem_m_membership_registered WHERE ( sc_rep_mem_share_loan_year.membership_no = sc_mem_m_membership_registered.membership_no ) and sc_rep_mem_share_loan_year.balance_date = '!confirm_date!' and sc_mem_m_membership_registered.member_group_no in ('9499','9498','a9000') and sc_rep_mem_share_loan_year.client_id = '000' and ( sc_rep_mem_share_loan_year.emer_balance > 0 or sc_rep_mem_share_loan_year.norm_balance > 0 or sc_rep_mem_share_loan_year.spec_balance > 0 ) ) as principal_balance_coop
from dual where 1 = 1
